n,m,mod=map(int,input().split())
mat=[]
for i in range(m):
    mat.append(list(input()))
dp=[[0]*n for i in range(n)]
dp[0][0]=1
for i in range(1,n):
    if mat[0][i]=='1':
        dp[0][i]=dp[0][i-1]
    else:
        dp[0][i]=0
for i in range(1,n):
    if mat[i][0]=='1':
        dp[i][0]=dp[i-1][0]
    else:
        dp[i][0]=0
for i in range(1,n):
    for j in range(1,n):
        if mat[i][j]=='1':
            dp[i][j]=(dp[i-1][j]+dp[i][j-1])%mod
        else:
            dp[i][j]=0
print(dp[n-1][n-1]%mod)
